"""
Internationalization module for SpinningCam.
Supports EN (English), TR (Turkish), ES (Spanish).
Add more languages by extending each entry in STRINGS.
"""

_lang = "EN"
_fallback = "EN"

LANGUAGES = ["EN", "TR", "ES"]
LANGUAGE_NAMES = {"EN": "English", "TR": "Türkçe", "ES": "Español"}


def set_language(lang: str):
    global _lang
    if lang in LANGUAGES:
        _lang = lang


def get_language() -> str:
    return _lang


def t(key: str) -> str:
    entry = STRINGS.get(key)
    if entry is None:
        return key
    return entry.get(_lang, entry.get(_fallback, key))


